import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Loader2, ImageIcon, Sparkles, Database, Trash, ArrowLeft, Tag, Eye, Edit2, Check, X, Calendar, Layers
} from 'lucide-react';

// --- ESTILOS MEJORADOS PARA CRUD ---
const containerStyle = { padding: '40px', maxWidth: '1300px', margin: '0 auto', fontFamily: 'sans-serif', background: '#f1f5f9', minHeight: '100vh' };
const cardStyle = { background: 'white', padding: '20px', borderRadius: '24px', border: '1px solid #e2e8f0', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)', transition: 'all 0.3s ease' };
const badgeStyle = { padding: '4px 12px', borderRadius: '20px', fontSize: '0.7rem', fontWeight: 'bold', textTransform: 'uppercase' };
const inputEditStyle = { width: '100%', padding: '10px', borderRadius: '10px', border: '2px solid #e2e8f0', marginBottom: '10px', outline: 'none', fontSize: '0.9rem' };

const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();
  const API_URL = "http://localhost:5000"; 
  const CLOUD_NAME = "dwpgncjgn";

  // ESTADOS
  const [filas, setFilas] = useState([{ id: Date.now(), producto: '', precioNuevo: '', precioViejo: '', stock: '', categoria: 'Almacén', fotoSugerida: null }]);
  const [publicados, setPublicados] = useState([]);
  const [galeria, setGaleria] = useState([]);
  const [fechasGlobales, setFechasGlobales] = useState({ inicio: '', fin: '' });
  const [cargando, setCargando] = useState(false);
  
  // ESTADO CRUD INDIVIDUAL
  const [editandoId, setEditandoId] = useState(null);
  const [tempData, setTempData] = useState({});

  const cargarPublicados = useCallback(async () => {
    try {
      const res = await axios.get(`${API_URL}/api/ofertas/local/${localId}`);
      setPublicados(res.data);
    } catch (e) { console.error("Error al leer datos", e); }
  }, [API_URL, localId]);

  useEffect(() => {
    cargarPublicados();
    axios.get(`${API_URL}/api/galeria`).then(res => setGaleria(res.data));
  }, [cargarPublicados]);

  // --- LÓGICA DE ACTUALIZACIÓN (U del CRUD) ---
  const handleUpdate = async (id) => {
    try {
      setCargando(true);
      await axios.put(`${API_URL}/api/ofertas/${id}`, tempData);
      setEditandoId(null);
      await cargarPublicados();
      alert("Producto actualizado con éxito");
    } catch (e) { alert("Error al actualizar"); } finally { setCargando(false); }
  };

  // --- LÓGICA DE ELIMINACIÓN (D del CRUD) ---
  const handleDelete = async (id) => {
    if (window.confirm("¿Estás seguro de que quieres eliminar este artículo permanentemente?")) {
      try {
        await axios.delete(`${API_URL}/api/ofertas/${id}`);
        cargarPublicados();
      } catch (e) { alert("Error al borrar"); }
    }
  };

  return (
    <div style={containerStyle}>
      {/* NAVEGACIÓN */}
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '40px' }}>
        <button onClick={() => navigate(-1)} style={btnBack}><ArrowLeft size={18}/> Salir al Panel</button>
        <div style={{ display: 'flex', gap: '10px' }}>
          <button style={{ background: '#fff', border: '1px solid #e2e8f0', padding: '10px 20px', borderRadius: '12px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' }}>
            <Database size={18} color="#e67e22"/> Galería de Fotos
          </button>
        </div>
      </div>

      {/* CARGA MASIVA (CREATE masivo) */}
      <section style={{ marginBottom: '60px' }}>
        <h2 style={{ display: 'flex', alignItems: 'center', gap: '10px', color: '#1e293b' }}><Plus circle color="#e67e22"/> Carga Rápida (Pegar desde Excel)</h2>
        <div style={{ ...cardStyle, marginTop: '20px' }}>
            {/* Aquí iría tu tabla de handlePaste que ya tenemos configurada */}
            <p style={{color: '#64748b', fontSize: '0.9rem'}}>Pegá aquí tus columnas: Producto | P. Nuevo | P. Viejo | Stock | Categoría</p>
            {/* ... (Resto del código de la tabla de pegado) ... */}
        </div>
      </section>

      {/* GESTIÓN INDIVIDUAL (READ / UPDATE / DELETE) */}
      <section>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '25px' }}>
          <h2 style={{ display: 'flex', alignItems: 'center', gap: '10px', color: '#1e293b' }}><Eye color="#3b82f6"/> Gestión de Artículos Publicados</h2>
          <span style={{ background: '#3b82f6', color: 'white', padding: '5px 15px', borderRadius: '10px', fontSize: '0.8rem' }}>{publicados.length} Productos en la nube</span>
        </div>

        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: '25px' }}>
          {publicados.map(prod => (
            <div key={prod._id} style={{ ...cardStyle, border: editandoId === prod._id ? '2px solid #3b82f6' : '1px solid #e2e8f0' }}>
              
              {/* CABECERA DE LA CARD */}
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '15px' }}>
                <span style={{ ...badgeStyle, background: '#fef3c7', color: '#d97706' }}><Layers size={12}/> {prod.categoria}</span>
                <div style={{ display: 'flex', gap: '8px' }}>
                  {editandoId === prod._id ? (
                    <>
                      <button onClick={() => handleUpdate(prod._id)} style={{ background: '#dcfce7', color: '#16a34a', border: 'none', padding: '8px', borderRadius: '8px', cursor: 'pointer' }}><Check size={18}/></button>
                      <button onClick={() => setEditandoId(null)} style={{ background: '#f1f5f9', color: '#64748b', border: 'none', padding: '8px', borderRadius: '8px', cursor: 'pointer' }}><X size={18}/></button>
                    </>
                  ) : (
                    <>
                      <button onClick={() => { setEditandoId(prod._id); setTempData(prod); }} style={{ background: '#eff6ff', color: '#3b82f6', border: 'none', padding: '8px', borderRadius: '8px', cursor: 'pointer' }}><Edit2 size={18}/></button>
                      <button onClick={() => handleDelete(prod._id)} style={{ background: '#fff1f2', color: '#e11d48', border: 'none', padding: '8px', borderRadius: '8px', cursor: 'pointer' }}><Trash size={18}/></button>
                    </>
                  )}
                </div>
              </div>

              {/* CONTENIDO EDITABLE O VISTA */}
              <div style={{ display: 'flex', gap: '15px' }}>
                <img src={`https://res.cloudinary.com/${CLOUD_NAME}/image/upload/w_100,h_100,c_fill/v1/${prod.publicId}`} style={{ width: '80px', height: '80px', borderRadius: '15px', objectFit: 'cover' }} alt={prod.producto}/>
                
                <div style={{ flex: 1 }}>
                  {editandoId === prod._id ? (
                    <>
                      <input style={inputEditStyle} value={tempData.producto} onChange={e => setTempData({...tempData, producto: e.target.value})} placeholder="Nombre del producto"/>
                      <div style={{ display: 'flex', gap: '5px' }}>
                        <input style={inputEditStyle} type="number" value={tempData.precioNuevo} onChange={e => setTempData({...tempData, precioNuevo: e.target.value})} placeholder="P. Nuevo"/>
                        <input style={inputEditStyle} type="number" value={tempData.precioViejo} onChange={e => setTempData({...tempData, precioViejo: e.target.value})} placeholder="P. Viejo"/>
                      </div>
                      <select style={inputEditStyle} value={tempData.categoria} onChange={e => setTempData({...tempData, categoria: e.target.value})}>
                        <option value="Almacén">Almacén</option>
                        <option value="Carnicería">Carnicería</option>
                        <option value="Lácteos">Lácteos</option>
                        <option value="Bebidas">Bebidas</option>
                      </select>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '5px', fontSize: '0.8rem', color: '#64748b' }}>
                         <Database size={14}/> Stock: <input style={{...inputEditStyle, width: '60px', marginBottom: 0}} type="number" value={tempData.stock} onChange={e => setTempData({...tempData, stock: e.target.value})}/>
                      </div>
                    </>
                  ) : (
                    <>
                      <h3 style={{ margin: '0 0 5px 0', fontSize: '1.1rem', color: '#1e293b' }}>{prod.producto}</h3>
                      <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
                        <span style={{ fontSize: '1.2rem', fontWeight: 'bold', color: '#e67e22' }}>${prod.precioNuevo}</span>
                        <span style={{ fontSize: '0.9rem', color: '#94a3b8', textDecoration: 'line-through' }}>${prod.precioViejo}</span>
                      </div>
                      <div style={{ marginTop: '10px', display: 'flex', flexDirection: 'column', gap: '4px' }}>
                        <span style={{ fontSize: '0.75rem', color: '#64748b', display: 'flex', alignItems: 'center', gap: '5px' }}><Database size={12}/> Stock disponible: <strong>{prod.stock}</strong></span>
                        <span style={{ fontSize: '0.75rem', color: '#64748b', display: 'flex', alignItems: 'center', gap: '5px' }}><Calendar size={12}/> Vence: {new Date(prod.fechaFinOferta).toLocaleDateString()}</span>
                      </div>
                    </>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
};

const btnBack = { background: 'none', border: 'none', color: '#64748b', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: 'bold' };

export default GestionOfertas;
